These work fine in the console, but when I try and run them within the document.ready of an external script, I get no luck at all.
I really hate javascript with a passion.  I haven't had to program using it for a good few years now, but I am doing some django frontend stuff and for an async image load to bootstrap carousel, I need to pause the carousel until the webworker has handed back the loaded blob and changed the source to it.   Currently I am trying an onload...
```
$(document).ready(function () {
    $("#carousel-large-background").on("slide.bs.carousel", function(e){
        next_el = $($('.carousel-item img').get(e.to))
        console.log("next_el = " + next_el)
        if (next_el.attr('src') == "")
        {
          var myCarouselEl = document.querySelector('#carousel-large-background')
          var carousel = new bootstrap.Carousel(myCarouselEl, {
            interval: false
          })
          console.log('src is empty.  next slide is : ' + next_el.get()[0])
          next_el.get(0).onload = function(){
            console.log("image has loaded")
            var myCarouselEl = document.querySelector('#carousel-large-background')
            var carousel = new bootstrap.Carousel(myCarouselEl, {
              interval: 5200
            });
            console.log(carousel)
          };
        }
    });
    ... webworker stuff below...
```
The webworker stuff works fine, but getting the stupid carousel to pause until the next image has loaded is proving to be a pain in the a**.  I guess I am probably having problems with event delegation or similar.  GAH!

However, the following works in the body of the document.ready:
```
 var myCarouselEl = document.querySelector('#carousel-large-background')
       var carousel = new bootstrap.Carousel(myCarouselEl, { interval: false })
```
and $('#carousel_id').carousel('pause') works in the slid event (but not the slide event).

```
    const myCarouselEl = document.querySelector('#carousel-large-background')
    myCarouselEl.addEventListener('slid.bs.carousel', function() {
    var carousel = new bootstrap.Carousel(myCarouselEl, {
         interval: false
     })
})
```

After two days stuck whit this problem i found the solution. This works for me:

```
 const myCarousel = document.getElementById('myCarousel');

  myCarousel.addEventListener('slide.bs.carousel', event => {
    //some custom code here, any time the carousel changes
  });

  //pause the Carousel
  jQuery("#mybuttonorsomethingelse").on('myevent', function () {
    var carousel = bootstrap.Carousel.getInstance(myCarousel) // Retrieve a Carousel instance
    carousel.to(<someindex>); //Cycles the carousel to a particular frame (0 based, similar to an array)
    carousel.pause(); //pause the carousel
  });

  //play the carousel
  jQuery("#mybuttonorsomethingelse").on('myotherevent', function () {
    var carousel = bootstrap.Carousel.getInstance(myCarousel) // Retrieve a Carousel instance
    carousel.cycle(); //play the carousel
  });
```

I hope this help you all.

