```
/* import the original Bootstrap files first */
@import "functions";
@import "variables";

// First override some or all individual color variables
$primary: $green-500;
$secondary: $pink-500;

// Then add them to your custom theme-colors map, together with any additional colors you might need
$theme-colors: (
  "primary":   $primary,
  "secondary": $secondary,
  "success":    $success,
  "info":       $info,
  "warning":    $warning,
  "danger":     $danger,
  "light":      $light,
  "dark":       $dark
);

/* finally, import Bootstrap to accept your changes */
@import "bootstrap";
