Hi @devhoussam1998 

In general, Bootstrap uses the `:invalid` and `:valid` pseudo-classes on an input field to determine its validity and displays the `invalid-feedback` or `valid-feedback`. The feedback must be placed after the input field and they must have a common parent.

But when we use `.input-group` and `.form-floating` together, the feedback has to be placed outside of `.form-floating`.

In this case `.is-invalid` and `.is-valid` classes have to be added to `form-floating` depending on the validity of the input field.

Replace your JS with the following and it should work as expected:

```Javascript
function toggleValidityClasses(input, formFloating) {
  if (input.checkValidity()) {
    formFloating.classList.add("is-valid");
    formFloating.classList.remove("is-invalid");
  } else {
    formFloating.classList.add("is-invalid");
    formFloating.classList.remove("is-valid");
  }
}

(function () {
  "use strict";

  // Fetch all the forms we want to apply validation styles to
  var forms = document.querySelectorAll(".needs-validation");

  // Loop over them and prevent submission
  Array.prototype.slice.call(forms).forEach(function (form) {
    form.addEventListener(
      "submit",
      function (event) {
        if (!form.checkValidity()) {
          event.preventDefault();
          event.stopPropagation();
        }

        form.classList.add("was-validated");

        // Add is-valid or is-invalid classes to form-floating
        var formFloating = form.querySelectorAll(".form-floating");

        Array.prototype.slice
          .call(formFloating)
          .forEach(function (formFloating) {
            var input = formFloating.querySelector(
              ".form-control, .form-select"
            );

            if (input) {
              toggleValidityClasses(input, formFloating);

              input.addEventListener("keyup", function () {
                toggleValidityClasses(input, formFloating);
              });
              input.addEventListener("change", function () {
                toggleValidityClasses(input, formFloating);
              });
            }
          });
      },
      false
    );
  });
})();
```

More info:
Check points 2 and 4 in the "How it works" section here: https://getbootstrap.com/docs/5.3/forms/validation/#how-it-works

